import { NAV_CATS, NAV_SECTIONS } from "../data";

// ── HEADER ────────────────────────────────────────────────
export default function Header({ activeCatNav, nav, saved, setShowMyTrails, isMobile }) {
  return (
    <header style={{ borderBottom:"1px solid #e8e8e8", position:"sticky", top:0, background:"#fff", zIndex:200 }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding: isMobile ? "10px 16px" : "0 60px", height: isMobile ? "auto" : 200 }}>
        <div style={{ width: isMobile ? "auto" : 180 }} />
        <button onClick={() => nav("home")} style={{ background:"none", border:"none", cursor:"pointer", textAlign:"center", padding: isMobile ? "4px 0" : "10px 0" }}>
          <img src="data:image/svg+xml;base64," alt="All Trails of Korea" style={{ height: isMobile ? 80 : 180, width:"auto", objectFit:"contain", display:"block" }} />
        </button>
        <div style={{ width: isMobile ? "auto" : 180 }} />
      </div>
      <nav style={{ display:"flex", alignItems:"center", justifyContent: isMobile ? "flex-start" : "center", borderTop:"1px solid #f0f0f0", padding: isMobile ? "0 8px" : "0 60px", overflowX: isMobile ? "auto" : "visible", scrollbarWidth:"none", gap: isMobile ? 0 : 28 }}>
        {NAV_CATS.map(item => (
          <NavBtn key={item.id} label={item.label} active={activeCatNav === item.id} onClick={() => nav(`cat:${item.id}`)} isMobile={isMobile} />
        ))}
        <div style={{ width:1, height:14, background:"#d8d8d8", flexShrink:0, margin: isMobile ? "0 4px" : "0 4px" }} />
        {NAV_SECTIONS.map(item => (
          <NavBtn key={item.id} label={item.label} active={activeCatNav === item.id} onClick={() => nav(item.id)} isMobile={isMobile} bold />
        ))}
        <div style={{ width:1, height:14, background:"#d8d8d8", flexShrink:0, margin: isMobile ? "0 4px" : "0 4px" }} />
        <button onClick={() => setShowMyTrails(true)} style={{ fontFamily:"'Cormorant Garamond',serif", fontSize: isMobile ? 9 : 11, letterSpacing:"0.18em", textTransform:"uppercase", background:"none", border:"none", cursor:"pointer", padding: isMobile ? "10px 10px" : "11px 0", whiteSpace:"nowrap", color:"#444", fontWeight:600, display:"flex", alignItems:"center", gap:6, flexShrink:0 }}>
          ◈ MY TRAILS {saved.length > 0 && <span style={{ background:"#111", color:"#fff", borderRadius:"50%", width:16, height:16, fontSize:8, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>{saved.length}</span>}
        </button>
      </nav>
    </header>
  );
}

function NavBtn({ label, active, onClick, isMobile, bold }) {
  return (
    <button onClick={onClick} style={{ fontFamily:"'Cormorant Garamond',serif", fontSize: isMobile ? 9 : 11, letterSpacing:"0.18em", textTransform:"uppercase", color: active ? "#111" : (bold ? "#444" : "#888"), background:"none", border:"none", borderBottom: active ? "1px solid #111" : "1px solid transparent", cursor:"pointer", padding: isMobile ? "10px 10px" : "11px 0", whiteSpace:"nowrap", fontWeight: bold ? 600 : 400, transition:"color 0.2s", flexShrink:0 }}>
      {label}
    </button>
  );
}
